#include<bits/stdc++.h>
using namespace std;
const int maxn = 24,INF=0x3f3f3f3f;
struct node
{
	int x,y;
}a[maxn+1];
int n,dp[1<<maxn|1],p[1<<maxn|1],dis[maxn+1][maxn+1];
int main()
{
	cin>>a[0].x>>a[0].y>>n;
	for(int i=1;i<=n;i++)cin>>a[i].x>>a[i].y;
	memset(dp,0x3f,sizeof(dp));
	for(int i=0;i<=n;i++)
	{
		for(int j=0;j<=n;j++)
		{
			dis[i][j]=(a[i].x-a[j].x)*(a[i].x-a[j].x)+(a[i].y-a[j].y)*(a[i].y-a[j].y);
			dis[j][i]=dis[i][j];
		}
	}
	dp[0]=0;
	for(int m=0;m<(1<<n);m++)
	{
		if(dp[m]==INF)continue; 
		for(int i=1;i<=n;i++)
		{
			if(m&1<<i-1)continue;
			for(int j=1;j<=n;j++)
			{
				if(m&1<<j-1)continue;
				if(dp[m|(1<<i-1)|(1<<j-1)]>dp[m]+dis[0][i]+dis[i][j]+dis[j][0])
                dp[m|(1<<i-1)|(1<<j-1)]=dp[m]+dis[0][i]+dis[i][j]+dis[j][0],p[m|(1<<i-1)|(1<<j-1)]=m;
			}
			break;
		}
	}
	cout<<dp[(1<<n)-1]<<endl;
	int cnt=(1<<n)-1;
	while (cnt!=0)
    {
        cout<<"0 ";
        int u=cnt^p[cnt];
        for (int i=1;i<=n;i++)
        if(u&1<<i-1)cout<<i<<" ";
        cnt=p[cnt];
    }
    cout<<0;
	return 0;
}
